import{getCachedAvailability,getCachedModels,setCachedAvailability}from"../lib/cache.js";import{createLogger}from"../lib/logger.js";import{AbstractProvider}from"./abstract-provider.js";import{ChromeFreeAIProvider}from"./chrome-free-ai-provider.js";import{GenericOpenAIProvider}from"./generic-openai-provider.js";import{LMStudioProvider}from"./lmstudio-provider.js";import{OllamaProvider}from"./ollama-provider.js";import{OpenAIProvider}from"./openai-provider.js";const log=createLogger("registry"),PROVIDER_CLASSES=[OpenAIProvider,ChromeFreeAIProvider,OllamaProvider,LMStudioProvider,GenericOpenAIProvider],VALID_PROVIDER_CLASSES=[],DROPPED=[];for(const P of PROVIDER_CLASSES)try{AbstractProvider.enforceContract(P),VALID_PROVIDER_CLASSES.push(P)}catch(err){DROPPED.push(`${P.name||P.id}: ${err.message}`)}DROPPED.length>0&&log.warn("Provider(s) excluded \u2014 contract violations:",DROPPED);const PROVIDERS_BY_ID=new Map(VALID_PROVIDER_CLASSES.map(P=>[P.id,P]));log.info(`Registered ${VALID_PROVIDER_CLASSES.length} / ${PROVIDER_CLASSES.length} provider(s): ${VALID_PROVIDER_CLASSES.map(P=>P.id).join(", ")}`);export function createProvider(providerId,apiKey,model,baseUrl){const ProviderClass=PROVIDERS_BY_ID.get(providerId);if(!ProviderClass){const available=VALID_PROVIDER_CLASSES.map(P=>P.id).join(", ");throw log.error(`Unknown provider "${providerId}". Available: ${available}`),new Error(`Unknown provider: "${providerId}". Available: ${available}`)}return log.debug(`Creating provider: ${ProviderClass.displayName} (model: ${model||ProviderClass.defaultModel})`),new ProviderClass(apiKey,model,baseUrl)}export async function getAvailableProviders(){const list=await Promise.all(VALID_PROVIDER_CLASSES.map(async P=>{let available=!0;if(P.isAvailable){const cached=getCachedAvailability(P.id);cached!==null?available=cached:(available=await P.isAvailable(),setCachedAvailability(P.id,available))}return available||log.info(`Provider ${P.id} is not available`),{id:P.id,name:P.displayName,keyPlaceholder:P.keyPlaceholder,requiresApiKey:P.requiresApiKey,models:P.models,get defaultModel(){const cached=getCachedModels(P.id);return cached&&cached.length>0?cached[0].id:P.defaultModel},available,_classRef:P}}));return log.info(`Available providers: ${list.filter(p=>p.available).map(p=>p.id).join(", ")}`),list}export function getProviderInfo(providerId){const ProviderClass=PROVIDERS_BY_ID.get(providerId);return ProviderClass?{id:ProviderClass.id,name:ProviderClass.displayName,keyPlaceholder:ProviderClass.keyPlaceholder,requiresApiKey:ProviderClass.requiresApiKey,models:ProviderClass.models,defaultModel:ProviderClass.defaultModel}:(log.warn(`getProviderInfo: unknown provider "${providerId}"`),null)}export async function unloadProviderModel(providerId,modelId){if(!providerId||!modelId)return;const ProviderClass=PROVIDERS_BY_ID.get(providerId);if(ProviderClass?.onModelUnloaded)try{await ProviderClass.onModelUnloaded(modelId)}catch(err){log.warn(`onModelUnloaded hook failed for ${providerId}: ${err.message}`)}}
